class Calculator:
    import math

    def add(self, a, b):
        return a + b

    def subtract(self, a, b):
        return a - b

    def multiply(self, a, b):
        return a * b

    def divide(self, a, b):
        if b == 0:
            return "Error! Division by zero."
        return a / b

    def power(self, base, exponent):
        return base ** exponent

    def square_root(self, x):
        if x < 0:
            return "Error! Square root of negative number."
        return math.sqrt(x)

    def factorial(self, n):
        if n < 0:
            return "Error! Factorial of negative number."
        return math.factorial(n)

    def logarithm(self, x, base):
        if x <= 0 or base <= 0 or base == 1:
            return "Error! Invalid input for logarithm."
        return math.log(x, base)

    def sine(self, angle):
        return math.sin(math.radians(angle))

    def cosine(self, angle):
        return math.cos(math.radians(angle))

    def tangent(self, angle):
        return math.tan(math.radians(angle))

    def cotangent(self, angle):
        return 1 / math.tan(math.radians(angle))

    def secant(self, angle):
        return 1 / math.cos(math.radians(angle))

    def cosecant(self, angle):
        return 1 / math.sin(math.radians(angle))

